def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 7:
            for a in range(1, 6):
                score -= 400 * (ratio - 7)**(2 + a/2)
                score += 60 * np.sin(ratio * np.pi * a * 1.7)
            for b in range(1, 10):
                score += np.exp(-0.9 * ratio * b) * np.cos(b * ratio * np.pi * 1.1) / (b ** 1.3)
            if capacity % 10 == 0:
                score -= 50 * np.log1p(ratio) + np.sin(ratio * capacity * 0.6)
        elif 6 < ratio <= 7:
            score -= 180 * (ratio - 6)**3.5 + 90 * np.cos(ratio * 6)
            for c in range(1, 9):
                if c % 2 == 0:
                    score += np.tanh(ratio * c) / (c ** 1.1)
                else:
                    score -= np.exp(-ratio * c) / (c + 2)
            for d in range(1, 5):
                score += ((-1) ** d) * np.sin(ratio * np.pi * d**1.2) / (d**1.8)
        elif 4 < ratio <= 6:
            val = (ratio - 4) ** 3.1
            score -= 130 * val + 55 * np.sin(ratio * 8)
            for e in range(1, 11):
                if e % 3 == 0:
                    score -= np.cosh(ratio * e / 3) / (e ** 1.4)
                else:
                    score += np.log1p(ratio * e) / (e + 1.5)
            score += np.sin(ratio * np.pi * 1.7) * np.tanh(val) * 0.7
        elif 2 < ratio <= 4:
            val2 = (ratio - 2) ** 2.9
            score -= 75 * val2 + 42 * np.cos(ratio * 12)
            for f in range(2, 13):
                if f % 4 == 0:
                    score -= np.exp(-ratio * f) / (f ** 1.5)
                else:
                    score += np.log1p(ratio * f) / (f + 0.7)
            for g in range(1, 8):
                score += ((-1) ** g) * np.sin(ratio * np.pi * 0.8 * g) / (g ** 1.9)
        elif 1 < ratio <= 2:
            val3 = (ratio - 1) ** 2.5
            score -= 45 * val3 + 35 * np.sin(ratio * 15)
            for h in range(1, 8):
                if h % 2 == 0:
                    score += np.tanh(ratio * np.pi * h) / (h ** 1.7)
                else:
                    score -= np.exp(-ratio * h) / (h + 0.5)
            for j in range(1,5):
                score += ((-1) ** j) * np.cos(ratio * np.pi * j**1.6) / (j**2)
        else:
            step = 0.07
            triggered = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    triggered = True
                    break
            if not triggered:
                score += 20 * (1 - ratio)**3 + 12 * np.cos(ratio * 20)
            for l in range(1, 7):
                score += np.exp(-1.5 * l * ratio) * np.cos(l * ratio * np.pi * 1.8) / (l ** 1.3)
        penalty = 0
        for m in range(1, 14):
            term = ((-1) ** m) * (ratio ** (2.5 * m)) / (m * 5.0)
            if m % 7 == 0:
                penalty += term * np.log1p(m * ratio)
            elif m % 5 == 0:
                penalty += term / (1 + np.exp(-m*ratio/4))
            elif m % 3 == 0:
                penalty -= term * np.sin(m * ratio * 1.9)
            elif m % 2 == 0:
                penalty += term * np.cos(ratio * m * 1.1)
            else:
                penalty -= term / (1 + ratio * m)
        score += penalty
        if item > capacity:
            score -= 280
            for n in range(1, 12):
                if capacity == 0:
                    break
                mod_value = item % (capacity + n)
                score += (mod_value ** 0.8) / (n ** 0.8)
                if mod_value > capacity * 0.75:
                    score -= 45 / n
            if capacity % 11 == 0:
                score -= 15 * np.tanh(ratio)
        elif (capacity - item) < 0.2 * capacity:
            score += 65
            for o in range(9):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((o + 1) * ratio * 4.2 * np.pi) / (o + 1)
                if (capacity - item) < 0.08 * capacity:
                    score += 11 * np.sin((o + 1) * ratio * 5.5)
            if capacity % 9 == 0:
                score += 10 * np.sin(ratio * capacity * 0.9)
        else:
            if ratio < 0.25:
                score -= 22 * np.exp(-ratio * 50) + 9 * np.sin(ratio * 40)
                for p in range(1, 12):
                    score += np.cos(ratio * np.pi * p * 1.7) / (p ** 3.8)
            if capacity % 5 == 0:
                score += 8 * np.log1p(capacity * ratio) - 7 * np.sin(ratio * 15)
        if capacity % 17 == 0:
            score += 8 * (np.log1p(capacity * 1.5) - ratio) + np.cos(ratio * capacity * 1.7)
        elif capacity % 11 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.6)) + np.sin((capacity + ratio) * 7)
        else:
            for q in range(1, 15):
                if (capacity + q) % 6 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.5 * np.cos(q * ratio * 1.6)
                else:
                    score -= 0.6 * np.sin(q * ratio * 1.9) / (q + 2)
        cap_int = int(capacity)
        if cap_int % 6 == 0 and ratio < 0.6:
            for r in range(1, 9):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.7) / (r ** 1.3)
        elif cap_int % 5 == 2 and ratio < 0.5:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 5.5 and capacity > 100:
            factor = 2.3
            for s in range(4, 9):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 3 == 0:
                    score += 3.1 * np.cos(s * ratio * 1.2)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
